const cleanArg = (v) => { const t = String(v == null ? '' : v).trim(); return /^\{[a-zA-Z0-9_]+\}$/.test(t) ? '' : t; };
const rawMode = cleanArg('{mode}').toLowerCase();
const mode = rawMode === 'preflight' ? 'preflight' : 'full';
const sleep = (ms) => new Promise((resolve) => setTimeout(resolve, ms));
const normalizeText = (value) => (value || '').replace(/\s+/g, ' ').trim();
const normalizeUrl = (raw) => {
  if (!raw) return '';
  try {
    return new URL(raw, window.location.origin).toString();
  } catch {
    return String(raw);
  }
};
const unique = (items) => Array.from(new Set((items || []).filter(Boolean)));
const uniqueByKey = (items, keyFn) => {
  const seen = new Set();
  const values = [];
  for (const item of items || []) {
    if (!item) continue;
    const key = String(keyFn(item) || '');
    if (!key || seen.has(key)) continue;
    seen.add(key);
    values.push(item);
  }
  return values;
};
const numericOrNull = (value) => {
  if (value === null || value === undefined || value === '') return null;
  const parsed = Number(value);
  return Number.isFinite(parsed) ? parsed : null;
};
const epochToIso = (value) => {
  const parsed = numericOrNull(value);
  if (!parsed) return null;
  const millis = parsed > 1e12 ? parsed : parsed * 1000;
  try {
    return new Date(millis).toISOString();
  } catch {
    return null;
  }
};
const slugify = (value) => normalizeText(value).replace(/[^a-zA-Z0-9_-]+/g, '_').replace(/^_+|_+$/g, '') || 'post';
const isVisible = (node) => {
  if (!(node instanceof Element)) return false;
  const rect = node.getBoundingClientRect();
  if (rect.width <= 0 || rect.height <= 0) return false;
  const style = window.getComputedStyle(node);
  return style.display !== 'none' && style.visibility !== 'hidden' && style.opacity !== '0';
};
const likelyMediaUrl = (raw) => {
  const url = normalizeUrl(raw);
  if (!/^https?:/i.test(url)) return '';
  if (/profile_pic|profile_pic_url|emoji|favicon/i.test(url)) return '';
  return url;
};
const waitForHydration = async () => {
  const deadline = Date.now() + 6000;
  while (Date.now() < deadline) {
    const hasTime = !!document.querySelector('main time, article time, time');
    const hasScript = Array.from(document.querySelectorAll('script')).some((node) => (node.textContent || '').includes('xdt_api__v1__media__shortcode__web_info'));
    const hasMedia = mode === 'full' && !!document.querySelector('main img, main video, article img, article video');
    if (hasTime || hasScript || hasMedia) return true;
    await sleep(300);
  }
  return true;
};
await waitForHydration();
const shortcodeFromUrl = (url) => {
  try {
    const match = new URL(url).pathname.match(/^\/(?:[^/]+\/)?(?:p|reel|tv)\/([^/?#]+)/i);
    return match ? match[1] : '';
  } catch {
    return '';
  }
};
const filenameStem = (url) => {
  try {
    const path = new URL(url).pathname.split('/').filter(Boolean).pop() || '';
    return path.toLowerCase();
  } catch {
    return '';
  }
};
const scoreCandidate = (candidate) => {
  if (!candidate || typeof candidate !== 'object') return -1;
  const width = numericOrNull(candidate.width) || 0;
  const height = numericOrNull(candidate.height) || 0;
  const bitrate = numericOrNull(candidate.bitrate) || 0;
  return (width * height) + bitrate;
};
const pickBest = (candidates) => {
  if (!Array.isArray(candidates) || !candidates.length) return '';
  const sorted = [...candidates].sort((left, right) => scoreCandidate(right) - scoreCandidate(left));
  return likelyMediaUrl(sorted[0]?.url || sorted.find((candidate) => candidate?.url)?.url || '');
};
const canonicalUrl = normalizeUrl(document.querySelector("link[rel='canonical']")?.getAttribute('href') || window.location.href);
const requestedShortcode = shortcodeFromUrl(canonicalUrl);
const timeNode = document.querySelector('main time, article time, time');
const postRoot = timeNode?.closest('article') || document.querySelector('main article') || document.querySelector('article') || document.querySelector('main') || document.body;
const hydrationScriptTexts = Array.from(document.querySelectorAll('script')).map((node) => node.textContent || '').filter((text) => text.includes('xdt_api__v1__media__shortcode__web_info') || text.includes('preview_comments') || text.includes('comments__connection') || text.includes('comment_count'));
const findWebInfo = (node, bucket = []) => {
  if (!node || typeof node !== 'object') return bucket;
  if (Array.isArray(node)) {
    for (const item of node) findWebInfo(item, bucket);
    return bucket;
  }
  const webInfo = node.xdt_api__v1__media__shortcode__web_info;
  if (webInfo && Array.isArray(webInfo.items)) bucket.push(...webInfo.items);
  for (const child of Object.values(node)) findWebInfo(child, bucket);
  return bucket;
};
const searchHydrationPayload = () => {
  const matchingScripts = hydrationScriptTexts.filter((text) => text.includes('xdt_api__v1__media__shortcode__web_info'));
  for (const text of matchingScripts) {
    try {
      const parsed = JSON.parse(text);
      const items = findWebInfo(parsed, []);
      const exact = items.find((item) => String(item?.code || '') === requestedShortcode);
      if (exact) return exact;
    } catch {
      // ignore invalid script text
    }
  }
  return null;
};
const collectMediaFromHydrationItem = (item) => {
  if (!item || typeof item !== 'object') return null;
  const mediaNodes = Array.isArray(item.carousel_media) && item.carousel_media.length ? item.carousel_media : [item];
  const assets = mediaNodes.map((media, index) => {
    const imageUrl = pickBest(media?.image_versions2?.candidates);
    const videoUrl = pickBest(media?.video_versions);
    return {
      position: index + 1,
      media_id: String(media?.pk || media?.id || '') || null,
      kind: videoUrl ? (imageUrl ? 'mixed' : 'video') : 'image',
      image_url: imageUrl || null,
      video_url: videoUrl || null,
      best_url: videoUrl || imageUrl || null
    };
  }).filter((asset) => asset.best_url || asset.image_url || asset.video_url);
  return {
    found: true,
    post_id: String(item?.pk || item?.id || '') || null,
    author_handle: normalizeText(item?.user?.username || item?.owner?.username || ''),
    caption: normalizeText(item?.caption?.text || ''),
    posted_at: item?.taken_at ? new Date(Number(item.taken_at) * 1000).toISOString() : null,
    media_type: item?.media_type || null,
    image_urls: unique(assets.map((asset) => asset.image_url).filter(Boolean)),
    video_urls: unique(assets.map((asset) => asset.video_url).filter(Boolean)),
    assets,
    stats: {
      like_count: numericOrNull(item?.like_count),
      comment_count: numericOrNull(item?.comment_count),
      play_count: numericOrNull(item?.play_count),
      view_count: numericOrNull(item?.view_count || item?.video_view_count),
      share_count: numericOrNull(item?.share_count || item?.reshare_count),
      save_count: numericOrNull(item?.save_count)
    }
  };
};
const hydrated = collectMediaFromHydrationItem(searchHydrationPayload()) || { found: false, post_id: null, image_urls: [], video_urls: [], author_handle: null, caption: null, posted_at: null, media_type: null, assets: [], stats: {} };
const collectOgUrls = (property) => unique(Array.from(document.querySelectorAll(`meta[property='${property}']`)).map((node) => likelyMediaUrl(node.getAttribute('content') || '')).filter(Boolean));
const flattenLdItems = (value, bucket = []) => {
  if (!value || typeof value !== 'object') return bucket;
  if (Array.isArray(value)) {
    for (const item of value) flattenLdItems(item, bucket);
    return bucket;
  }
  const typeValue = value['@type'];
  const typeText = Array.isArray(typeValue) ? typeValue.join(' ') : String(typeValue || '');
  if (/SocialMediaPosting|ImageObject|VideoObject/i.test(typeText)) bucket.push(value);
  for (const child of Object.values(value)) flattenLdItems(child, bucket);
  return bucket;
};
const mediaFromLd = () => {
  const images = [];
  const videos = [];
  const captions = [];
  const timestamps = [];
  for (const script of Array.from(document.querySelectorAll("script[type='application/ld+json']"))) {
    const text = script.textContent || '';
    if (!text.trim()) continue;
    try {
      const parsed = JSON.parse(text);
      const entries = flattenLdItems(parsed, []);
      for (const entry of entries) {
        const typeValue = entry['@type'];
        const typeText = Array.isArray(typeValue) ? typeValue.join(' ') : String(typeValue || '');
        if (entry.uploadDate) timestamps.push(String(entry.uploadDate));
        if (entry.caption) captions.push(String(entry.caption));
        if (entry.articleBody) captions.push(String(entry.articleBody));
        if (/SocialMediaPosting|ImageObject/i.test(typeText)) {
          const imageValue = entry.image;
          const imageCandidates = Array.isArray(imageValue) ? imageValue : imageValue ? [imageValue] : [];
          for (const candidate of imageCandidates) {
            if (typeof candidate === 'string') images.push(candidate);
            else if (candidate && typeof candidate === 'object') images.push(candidate.url || candidate.contentUrl || candidate.thumbnailUrl || '');
          }
        }
        if (/SocialMediaPosting|VideoObject/i.test(typeText)) {
          const videoValue = entry.video;
          const videoCandidates = Array.isArray(videoValue) ? videoValue : videoValue ? [videoValue] : [];
          for (const candidate of videoCandidates) {
            if (typeof candidate === 'string') videos.push(candidate);
            else if (candidate && typeof candidate === 'object') videos.push(candidate.contentUrl || candidate.url || '');
          }
          videos.push(entry.contentUrl || entry.url || '');
        }
      }
    } catch {
      // ignore non-JSON or obfuscated blobs
    }
  }
  return {
    image_urls: unique(images.map(likelyMediaUrl).filter(Boolean)),
    video_urls: unique(videos.map(likelyMediaUrl).filter(Boolean)),
    timestamps: unique(timestamps.filter(Boolean)),
    captions: unique(captions.map(normalizeText).filter(Boolean))
  };
};
const domImageCandidates = (scope) => unique(Array.from(scope.querySelectorAll('img')).filter((node) => {
  if (!(node instanceof HTMLImageElement)) return false;
  if (!isVisible(node)) return false;
  const alt = normalizeText(node.getAttribute('alt') || '');
  if (/profile picture/i.test(alt)) return false;
  const width = node.naturalWidth || node.width || node.getBoundingClientRect().width || 0;
  const height = node.naturalHeight || node.height || node.getBoundingClientRect().height || 0;
  if (width < 240 && height < 240) return false;
  return true;
}).map((node) => likelyMediaUrl(node.currentSrc || node.getAttribute('src') || '')).filter(Boolean));
const domVideoCandidates = (scope) => {
  const direct = Array.from(scope.querySelectorAll('video')).filter(isVisible).map((node) => likelyMediaUrl(node.currentSrc || node.getAttribute('src') || ''));
  const sources = Array.from(scope.querySelectorAll('video source')).filter((node) => isVisible(node.parentElement || node)).map((node) => likelyMediaUrl(node.getAttribute('src') || ''));
  return unique([...direct, ...sources].filter(Boolean));
};
const visibleMediaSignature = () => unique([...domImageCandidates(postRoot), ...domVideoCandidates(postRoot)]).sort().join('|');
const labelOf = (node) => normalizeText(node?.getAttribute?.('aria-label') || node?.getAttribute?.('title') || node?.innerText || node?.textContent || '');
const findNextButton = () => {
  const scopedButtons = Array.from(postRoot.querySelectorAll("button, [role='button']")).filter(isVisible);
  const buttons = scopedButtons.length ? scopedButtons : Array.from(document.querySelectorAll("button, [role='button']")).filter(isVisible);
  for (const node of buttons) {
    const label = labelOf(node);
    if (/^next$/i.test(label) || /next slide|next item|go to next/i.test(label)) return node;
    const iconLabels = Array.from(node.querySelectorAll('svg, title')).map(labelOf).filter(Boolean).join(' ');
    if (/next/i.test(iconLabels)) return node;
  }
  return null;
};
const normalizeHydrationComment = (node) => {
  if (!node || typeof node !== 'object') return null;
  const text = normalizeText(node.text || node.content || node.body?.text || '');
  const userHandle = normalizeText(node.user?.username || node.owner?.username || node.author?.username || '');
  if (!text || !userHandle) return null;
  return {
    comment_id: String(node.pk || node.id || node.comment_id || '') || null,
    user_handle: userHandle,
    text,
    created_at: epochToIso(node.created_at || node.created_at_utc || node.created_at_time),
    like_count: numericOrNull(node.comment_like_count || node.like_count),
    reply_count: numericOrNull(node.child_comment_count || node.reply_count)
  };
};
const collectCommentsFromHydrationScripts = () => {
  const comments = [];
  const walk = (node, path = []) => {
    if (!node || typeof node !== 'object') return;
    if (Array.isArray(node)) {
      for (const item of node) walk(item, path);
      return;
    }
    const loweredPath = path.join('.').toLowerCase();
    if (loweredPath.includes('comment')) {
      const comment = normalizeHydrationComment(node);
      if (comment) comments.push(comment);
    }
    for (const [key, child] of Object.entries(node)) walk(child, [...path, key]);
  };
  for (const text of hydrationScriptTexts) {
    try {
      walk(JSON.parse(text), []);
    } catch {
      // ignore invalid script blobs
    }
  }
  return uniqueByKey(comments, (comment) => `${comment.comment_id || ''}|${comment.user_handle}|${comment.text}|${comment.created_at || ''}`);
};
const collectVisibleComments = (authorHandleHint, captionHint) => {
  const rows = Array.from(postRoot.querySelectorAll('ul li')).filter(isVisible);
  const comments = [];
  for (const row of rows) {
    const userLink = Array.from(row.querySelectorAll("a[href^='/']")).find(isVisible);
    const userHandle = normalizeText(userLink?.getAttribute('href')?.split('/')?.filter(Boolean)?.[0] || userLink?.textContent || '');
    if (!userHandle) continue;
    const rawText = normalizeText(row.textContent || '');
    if (!rawText) continue;
    let text = rawText;
    if (text.toLowerCase().startsWith(userHandle.toLowerCase())) text = normalizeText(text.slice(userHandle.length));
    text = normalizeText(text.replace(/\b\d+\s*[smhdwy]\b/ig, ' ').replace(/\b\d+\s+likes?\b/ig, ' ').replace(/\bReply\b/ig, ' '));
    if (!text) continue;
    if (captionHint && text == captionHint) continue;
    if (authorHandleHint && userHandle.toLowerCase() == String(authorHandleHint).toLowerCase() && captionHint && text.includes(captionHint.slice(0, Math.min(24, captionHint.length)))) continue;
    const likeMatch = rawText.match(/(\d+)\s+likes?/i);
    comments.push({
      comment_id: null,
      user_handle: userHandle,
      text,
      created_at: row.querySelector('time')?.getAttribute('datetime') || null,
      like_count: likeMatch ? Number(likeMatch[1]) : null,
      reply_count: null
    });
  }
  return uniqueByKey(comments, (comment) => `${comment.user_handle}|${comment.text}|${comment.created_at || ''}`);
};
const metaDescription = document.querySelector("meta[property='og:description'], meta[name='description']")?.getAttribute('content') || '';
const ld = mode === 'full' ? mediaFromLd() : { image_urls: [], video_urls: [], timestamps: [], captions: [] };
const postedAt = hydrated.posted_at || timeNode?.getAttribute('datetime') || document.querySelector("meta[property='article:published_time']")?.getAttribute('content') || ld.timestamps[0] || null;
const caption = hydrated.caption || ld.captions[0] || normalizeText(metaDescription) || normalizeText(postRoot.querySelector('h1')?.textContent || '') || null;
const authorHandle = hydrated.author_handle || normalizeText(postRoot.querySelector("header a[href^='/']")?.getAttribute('href')?.split('/')?.filter(Boolean)?.[0] || '') || null;
let imageUrls = [];
let videoUrls = [];
let assetList = [];
let comments = [];
const carouselImages = [];
const carouselVideos = [];
const seenStates = new Set();
let viewerClicks = 0;
let ogImages = [];
let ogVideos = [];
if (mode === 'full') {
  ogImages = collectOgUrls('og:image');
  ogVideos = unique([...collectOgUrls('og:video'), ...collectOgUrls('og:video:url')]);
  for (let pass = 0; pass < 8; pass += 1) {
    const images = domImageCandidates(postRoot);
    const videos = domVideoCandidates(postRoot);
    for (const image of images) carouselImages.push(image);
    for (const video of videos) carouselVideos.push(video);
    const state = unique([...images, ...videos]).sort().join('|');
    if (state) {
      if (seenStates.has(state) && pass > 0) break;
      seenStates.add(state);
    }
    const next = findNextButton();
    if (!next) break;
    next.click();
    viewerClicks += 1;
    await sleep(650);
    const afterState = visibleMediaSignature();
    if (!afterState || (state && afterState === state)) break;
  }
  imageUrls = unique([...hydrated.image_urls, ...ld.image_urls, ...ogImages, ...(hydrated.found ? [] : carouselImages)]).filter((url) => !/\.mp4($|\?)/i.test(filenameStem(url)));
  videoUrls = unique([...hydrated.video_urls, ...ld.video_urls, ...ogVideos, ...(hydrated.found ? [] : carouselVideos)]);
  const domAssets = uniqueByKey([
    ...unique(carouselImages).map((url, index) => ({ position: index + 1, kind: 'image', image_url: url, video_url: null, best_url: url, media_id: null, source: 'viewer' })),
    ...unique(carouselVideos).map((url, index) => ({ position: index + 1, kind: 'video', image_url: null, video_url: url, best_url: url, media_id: null, source: 'viewer' }))
  ], (asset) => asset.best_url || `${asset.kind}|${asset.position}`);
  const merged = uniqueByKey([
    ...(Array.isArray(hydrated.assets) ? hydrated.assets.map((asset) => ({ ...asset, source: 'hydration' })) : []),
    ...(!hydrated.found ? domAssets : [])
  ], (asset) => asset.best_url || asset.image_url || asset.video_url || `${asset.kind}|${asset.position}`);
  assetList = merged.length ? merged : [
    ...imageUrls.map((url, index) => ({ position: index + 1, kind: 'image', image_url: url, video_url: null, best_url: url, media_id: null, source: 'fallback' })),
    ...videoUrls.map((url, index) => ({ position: index + 1, kind: 'video', image_url: null, video_url: url, best_url: url, media_id: null, source: 'fallback' }))
  ];
  const hydrationComments = collectCommentsFromHydrationScripts();
  const visibleComments = collectVisibleComments(authorHandle, caption);
  comments = uniqueByKey([...hydrationComments, ...visibleComments], (comment) => `${comment.comment_id || ''}|${comment.user_handle}|${comment.text}|${comment.created_at || ''}`).slice(0, 80);
} else {
  imageUrls = unique(hydrated.image_urls);
  videoUrls = unique(hydrated.video_urls);
  assetList = Array.isArray(hydrated.assets) ? hydrated.assets.map((asset) => ({ ...asset, source: 'hydration' })) : [];
}
const mediaKindFromHydration = hydrated.found ? (hydrated.media_type === 8 ? 'carousel' : hydrated.media_type === 2 ? 'video' : hydrated.media_type === 1 ? 'image' : null) : null;
const hydrationAssetCount = Array.isArray(hydrated.assets) ? hydrated.assets.length : 0;
const mediaKind = /\/reel\//i.test(canonicalUrl) ? 'reel' : /\/tv\//i.test(canonicalUrl) ? 'tv' : mediaKindFromHydration || (hydrationAssetCount > 1 ? 'carousel' : videoUrls.length && !imageUrls.length ? 'video' : videoUrls.length && imageUrls.length ? 'mixed' : imageUrls.length > 1 && !hydrated.found ? 'carousel' : 'image');
const postKey = hydrated.post_id || requestedShortcode || null;
return {
  mode,
  post_url: canonicalUrl,
  shortcode: requestedShortcode || null,
  post_id: hydrated.post_id,
  post_key: postKey,
  post_slug: slugify(`${postKey || 'post'}_${String(postedAt || 'undated').slice(0, 10)}`),
  kind: mediaKind,
  posted_at: postedAt,
  caption,
  author_handle: authorHandle,
  image_urls: imageUrls,
  video_urls: videoUrls,
  asset_urls: unique([...imageUrls, ...videoUrls]),
  asset_count: assetList.length,
  assets: assetList,
  stats: {
    like_count: numericOrNull(hydrated.stats?.like_count),
    comment_count: numericOrNull(hydrated.stats?.comment_count) || (comments.length || null),
    play_count: numericOrNull(hydrated.stats?.play_count),
    view_count: numericOrNull(hydrated.stats?.view_count),
    share_count: numericOrNull(hydrated.stats?.share_count),
    save_count: numericOrNull(hydrated.stats?.save_count)
  },
  comments,
  viewer_observed: {
    root_detected: !!postRoot,
    visible_state_count: seenStates.size,
    carousel_clicks: viewerClicks,
    visible_image_count: unique(carouselImages).length,
    visible_video_count: unique(carouselVideos).length
  },
  resolved_via: {
    hydration_blob: hydrated.found,
    ld_json: !!(ld.image_urls.length || ld.video_urls.length),
    open_graph: !!(ogImages.length || ogVideos.length),
    dom_carousel: seenStates.size > 0,
    carousel_clicks: viewerClicks > 0,
    time_node: !!timeNode
  }
};
